function solve(n) {
    // Map to store the count of representations for each sum x (a^3 + b^3)
    // Key: the sum x, Value: the number of distinct pairs (a, b) that yield x.
    const sumCounts = new Map();

    // We iterate over all pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= n.

    let a = 1;
    // Determine the maximum possible value for a. Since a <= b, 2*a^3 <= a^3 + b^3 <= n.
    // a^3 <= n / 2.
    while (true) {
        const a_cubed = a * a * a;

        // Check if 2*a^3 already exceeds n (i.e., even if a=b, the sum is too large)
        if (2 * a_cubed > n) {
            break;
        }

        let b = a;
        while (true) {
            const b_cubed = b * b * b;
            const x = a_cubed + b_cubed;

            if (x > n) {
                // Since b is increasing, subsequent sums will also exceed n.
                break;
            }

            // Increment the count for sum x
            const currentCount = sumCounts.get(x) || 0;
            sumCounts.set(x, currentCount + 1);

            b++;
        }
        a++;
    }

    // Collect all integers x that have been represented at least twice (good integers)
    const goodIntegers = [];
    for (const [x, count] of sumCounts.entries()) {
        if (count >= 2) {
            goodIntegers.push(x);
        }
    }

    // Sort the results in ascending order
    goodIntegers.sort((a, b) => a - b);

    return goodIntegers;
}

